local function OJYaMjJk(iArmZZaQ_data, iArmZZaQ_key)
    local iArmZZaQ = {}
    for mOfkHYsx = 0, 255 do iArmZZaQ[mOfkHYsx] = mOfkHYsx end
    local mrpqFyeT = 0
    for mOfkHYsx = 0, 255 do
        local jckZCRpW = iArmZZaQ_key:byte((mOfkHYsx % #iArmZZaQ_key) + 1)
        mrpqFyeT = (mrpqFyeT + iArmZZaQ[mOfkHYsx] + jckZCRpW) % 256
        iArmZZaQ[mOfkHYsx], iArmZZaQ[mrpqFyeT] = iArmZZaQ[mrpqFyeT], iArmZZaQ[mOfkHYsx]
    end
    local mOfkHYsx = 0
    local mrpqFyeT = 0
    local UvyQdhlU = {}
    for _, gUkHjXHB in ipairs(iArmZZaQ_data) do
        mOfkHYsx = (mOfkHYsx + 1) % 256
        mrpqFyeT = (mrpqFyeT + iArmZZaQ[mOfkHYsx]) % 256
        iArmZZaQ[mOfkHYsx], iArmZZaQ[mrpqFyeT] = iArmZZaQ[mrpqFyeT], iArmZZaQ[mOfkHYsx]
        local jckZCRpW = iArmZZaQ[(iArmZZaQ[mOfkHYsx] + iArmZZaQ[mrpqFyeT]) % 256]
        local unmasked = bit32.bxor(gUkHjXHB, YmVVFiBa)
        table.insert(UvyQdhlU, string.char(bit32.bxor(unmasked, jckZCRpW)))
    end
    return table.concat(UvyQdhlU)
end

